class Solution {
public:
    int minSteps(int n) {
        if (n == 1) {
            return 0;
        }
        int steps = 0;
        int currentA = 1;
        while (currentA < n) {
            currentA *= 2;
            steps++;
        }
        return steps;
    }
};
```
